import React, { useState } from 'react';
import { menuCategories } from './menuData';
import './Menu.css';

const Menu = () => {
  const [activeCategory, setActiveCategory] = useState(1);
  const [cart, setCart] = useState([]);
  const [showCart, setShowCart] = useState(false);
  const [selectedItem, setSelectedItem] = useState(null);

  const handleAddToCart = (item) => {
    setCart([...cart, { ...item, cartId: Date.now() }]);
  };

  const handleRemoveFromCart = (cartId) => {
    setCart(cart.filter(item => item.cartId !== cartId));
  };

  const getCartTotal = () => {
    return cart.reduce((total, item) => total + item.price, 0);
  };

  const activeCategoryData = menuCategories.find(cat => cat.id === activeCategory);

  const handleItemClick = (item) => {
    // Only show modal for items with recipe details (IDs 1-10)
    if (item.id <= 10 && item.recipeDetails) {
      setSelectedItem(item);
    }
  };

  const closeModal = () => {
    setSelectedItem(null);
  };

  // Render recipe details modal
  const renderRecipeModal = () => {
    if (!selectedItem || !selectedItem.recipeDetails) return null;

    const recipe = selectedItem.recipeDetails;

    return (
      <div className="modal-overlay" onClick={closeModal}>
        <div className="recipe-modal" onClick={(e) => e.stopPropagation()}>
          <button className="modal-close" onClick={closeModal}>
            <i className="fas fa-times"></i>
          </button>
          
          <div className="recipe-modal-header">
            <img src={selectedItem.image} alt={selectedItem.name} />
            <div className="recipe-header-content">
              <h2>{selectedItem.name}</h2>
              <p>{selectedItem.description}</p>
              <div className="recipe-meta">
                <span><i className="fas fa-clock"></i> Prep: {recipe.prepTime}</span>
                <span><i className="fas fa-fire"></i> Cook: {recipe.cookTime}</span>
                <span><i className="fas fa-users"></i> Serves: {recipe.servings}</span>
              </div>
              {recipe.benefits && (
                <div className="recipe-benefits">
                  {recipe.benefits.map((benefit, idx) => (
                    <span key={idx} className="benefit-tag">{benefit}</span>
                  ))}
                </div>
              )}
            </div>
          </div>

          <div className="recipe-modal-body">
            {/* Ingredients Section */}
            {(recipe.ingredients || recipe.saladIngredients || recipe.baseIngredients || recipe.doughIngredients) && (
              <div className="recipe-section">
                <h3><i className="fas fa-list-ul"></i> Ingredients</h3>
                <ul className="ingredients-list">
                  {(recipe.ingredients || recipe.saladIngredients || recipe.baseIngredients || recipe.doughIngredients || []).map((ingredient, idx) => (
                    <li key={idx}>{ingredient}</li>
                  ))}
                  {/* Additional ingredients for specific recipes */}
                  {recipe.chutneyIngredients && recipe.chutneyIngredients.map((ingredient, idx) => (
                    <li key={`chutney-${idx}`}>{ingredient}</li>
                  ))}
                  {recipe.temperingIngredients && recipe.temperingIngredients.map((ingredient, idx) => (
                    <li key={`temp-${idx}`}>{ingredient}</li>
                  ))}
                  {recipe.stuffingIngredients && recipe.stuffingIngredients.map((ingredient, idx) => (
                    <li key={`stuff-${idx}`}>{ingredient}</li>
                  ))}
                  {recipe.dressingIngredients && recipe.dressingIngredients.map((ingredient, idx) => (
                    <li key={`dress-${idx}`}>{ingredient}</li>
                  ))}
                </ul>
              </div>
            )}

            {/* Preparation Steps */}
            {recipe.preparationSteps && (
              <div className="recipe-section">
                <h3><i className="fas fa-clipboard-list"></i> Preparation Steps</h3>
                <ol className="steps-list">
                  {recipe.preparationSteps.map((step, idx) => (
                    <li key={idx}>{step}</li>
                  ))}
                  {recipe.chutneySteps && recipe.chutneySteps.map((step, idx) => (
                    <li key={`chutney-step-${idx}`}>{step}</li>
                  ))}
                  {recipe.assemblySteps && recipe.assemblySteps.map((step, idx) => (
                    <li key={`assembly-${idx}`}>{step}</li>
                  ))}
                </ol>
              </div>
            )}

            {/* Optional Additions */}
            {recipe.optionalAdditions && (
              <div className="recipe-section">
                <h3><i className="fas fa-plus-circle"></i> Optional Additions</h3>
                <ul className="optional-list">
                  {recipe.optionalAdditions.map((item, idx) => (
                    <li key={idx}>{item}</li>
                  ))}
                  {recipe.optionalAddons && recipe.optionalAddons.map((item, idx) => (
                    <li key={`addon-${idx}`}>{item}</li>
                  ))}
                </ul>
              </div>
            )}

            {/* Variations */}
            {recipe.variations && (
              <div className="recipe-section">
                <h3><i className="fas fa-magic"></i> Variations</h3>
                <ul className="variations-list">
                  {recipe.variations.map((variation, idx) => (
                    <li key={idx}>{variation}</li>
                  ))}
                </ul>
              </div>
            )}

            {/* Nutritional Info */}
            {recipe.nutritionalInfo && (
              <div className="recipe-section nutritional-section">
                <h3><i className="fas fa-chart-pie"></i> Nutritional Information</h3>
                <div className="nutritional-grid">
                  {Object.entries(recipe.nutritionalInfo).map(([key, value]) => (
                    <div key={key} className="nutrient-item">
                      <span className="nutrient-label">{key.replace(/([A-Z])/g, ' $1').trim()}</span>
                      <span className="nutrient-value">{value}</span>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* Serving Suggestion */}
            {recipe.servingSuggestion && (
              <div className="recipe-section">
                <h3><i className="fas fa-utensils"></i> Serving Suggestion</h3>
                <p>{recipe.servingSuggestion}</p>
              </div>
            )}

            {/* Storage Tips */}
            {recipe.storageTips && (
              <div className="recipe-section storage-tips">
                <h3><i className="fas fa-box"></i> Storage Tips</h3>
                <p>{recipe.storageTips}</p>
              </div>
            )}
          </div>

          <div className="recipe-modal-footer">
            <span className="recipe-price">₹{selectedItem.price}</span>
            <button className="add-btn" onClick={() => {
              handleAddToCart(selectedItem);
              closeModal();
            }}>
              Add to Cart
            </button>
          </div>
        </div>
      </div>
    );
  };

  return (
    <div className="menu-page">
      {/* Menu Header */}
      <section className="menu-hero">
        <div className="menu-hero-content">
          <h1>Our Menu</h1>
          <p>Explore our delicious range of dishes</p>
        </div>
      </section>

      <div className="menu-container">
        {/* Category Sidebar */}
        <aside className="category-sidebar">
          <h3>Categories</h3>
          <ul className="category-list">
            {menuCategories.map(category => (
              <li 
                key={category.id}
                className={`category-item ${activeCategory === category.id ? 'active' : ''}`}
                onClick={() => setActiveCategory(category.id)}
              >
                <i className={`fas ${category.icon}`}></i>
                <span>{category.name}</span>
                <span className="item-count">{category.items.length}</span>
              </li>
            ))}
          </ul>
        </aside>

        {/* Menu Items */}
        <main className="menu-content">
          <div className="category-header">
            <h2>
              <i className={`fas ${activeCategoryData?.icon}`}></i>
              {activeCategoryData?.name}
            </h2>
            <span className="item-total">{activeCategoryData?.items.length} items</span>
          </div>

          <div className="menu-items-grid">
            {activeCategoryData?.items.map(item => (
              <div 
                key={item.id} 
                className={`menu-item-card ${item.id <= 10 && item.recipeDetails ? 'clickable' : ''}`}
                onClick={() => handleItemClick(item)}
              >
                <div className="menu-item-info">
                  <h4>{item.name}</h4>
                  <p>{item.description}</p>
                </div>
                <div className="menu-item-action">
                  <span className="menu-item-price">₹{item.price}</span>
                  <button 
                    className="add-btn"
                    onClick={(e) => {
                      e.stopPropagation();
                      handleAddToCart(item);
                    }}
                  >
                    Add +
                  </button>
                </div>
              </div>
            ))}
          </div>
        </main>

        {/* Cart Sidebar */}
        <aside className={`cart-sidebar ${showCart ? 'open' : ''}`}>
          <div className="cart-header">
            <h3>Your Cart</h3>
            <button className="close-cart" onClick={() => setShowCart(false)}>
              <i className="fas fa-times"></i>
            </button>
          </div>
          
          <div className="cart-items">
            {cart.length === 0 ? (
              <div className="empty-cart">
                <i className="fas fa-shopping-cart"></i>
                <p>Your cart is empty</p>
              </div>
            ) : (
              cart.map(item => (
                <div key={item.cartId} className="cart-item">
                  <div className="cart-item-info">
                    <h5>{item.name}</h5>
                    <span className="cart-item-price">₹{item.price}</span>
                  </div>
                  <button 
                    className="remove-btn"
                    onClick={() => handleRemoveFromCart(item.cartId)}
                  >
                    <i className="fas fa-trash"></i>
                  </button>
                </div>
              ))
            )}
          </div>

          {cart.length > 0 && (
            <div className="cart-footer">
              <div className="cart-total">
                <span>Total</span>
                <span className="total-amount">₹{getCartTotal()}</span>
              </div>
              <button className="checkout-btn">Checkout</button>
            </div>
          )}
        </aside>
      </div>

      {/* Floating Cart Button */}
      {cart.length > 0 && !showCart && (
        <button className="floating-cart" onClick={() => setShowCart(true)}>
          <i className="fas fa-shopping-cart"></i>
          <span className="cart-count">{cart.length}</span>
        </button>
      )}

      {/* Recipe Detail Modal */}
      {renderRecipeModal()}
    </div>
  );
};

export default Menu;
